import * as fs from "fs";
import * as path from "path";
import { fileURLToPath } from "url";
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const LESSONS_DIR = path.join(__dirname, "../client/src/data/lessons");
function escapeStr(s: string): string { return s.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/"/g, '\\"').replace(/\n/g, "\\n"); }
function injectLesson(id: string, lesson: any): boolean {
  const files = fs.readdirSync(LESSONS_DIR).filter(f => f.endsWith(".ts") && f !== "index.ts" && f !== "types.ts");
  for (const file of files) {
    const fp = path.join(LESSONS_DIR, file);
    let src = fs.readFileSync(fp, "utf-8");
    if (!src.includes(`"${id}"`)) continue;
    const re = new RegExp(`"${id}":\\s*\\{[\\s\\S]*?\\[WRITE YOUR[\\s\\S]*?\\n  \\}`, "m");
    if (!re.test(src)) { console.log(`  ${id}: no placeholder in ${file}`); return false; }
    const fl: string[] = [];
    fl.push(`    title: "${escapeStr(lesson.title)}",`);
    fl.push(`    cellular: { title: "${escapeStr(lesson.cellular.title)}", content: "${escapeStr(lesson.cellular.content)}" },`);
    fl.push(`    riskFactors: [${lesson.riskFactors.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
    fl.push(`    diagnostics: [${lesson.diagnostics.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
    fl.push(`    management: [${lesson.management.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
    fl.push(`    nursingActions: [${lesson.nursingActions.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
    if (lesson.assessmentFindings) fl.push(`    assessmentFindings: [${lesson.assessmentFindings.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
    if (lesson.signs) fl.push(`    signs: { left: [${lesson.signs.left.map((r:string) => `"${escapeStr(r)}"`).join(",")}], right: [${lesson.signs.right.map((r:string) => `"${escapeStr(r)}"`).join(",")}] },`);
    if (lesson.medications) fl.push(`    medications: [${lesson.medications.map((m:any) => `{ name: "${escapeStr(m.name)}", type: "${escapeStr(m.type)}", action: "${escapeStr(m.action)}", sideEffects: "${escapeStr(m.sideEffects)}", contra: "${escapeStr(m.contra)}", pearl: "${escapeStr(m.pearl)}" }`).join(",")}],`);
    src = src.replace(re, `"${id}": {\n    ${fl.join("\n    ")}\n  }`);
    fs.writeFileSync(fp, src, "utf-8");
    console.log(`  Injected: ${id} -> ${file}`);
    return true;
  }
  console.log(`  NOT FOUND: ${id}`);
  return false;
}

const lessons: Record<string, any> = {
  "patient-positioning-rpn": {
    title: "Patient Positioning and Body Mechanics",
    cellular: { title: "Therapeutic Positioning, Transfers, and Safe Patient Handling", content: "Patient positioning is a fundamental nursing skill that directly impacts patient safety, comfort, respiratory function, skin integrity, and therapeutic outcomes. Proper positioning requires understanding of body alignment, center of gravity, base of support, and the biomechanical principles that guide safe patient handling and movement. Body mechanics refers to the coordinated effort of muscles, bones, and the nervous system to maintain balance, posture, and alignment during movement; the practical nurse must apply ergonomic principles to protect both the patient and themselves from injury. Key therapeutic positions include: supine (dorsal recumbent -- flat on back, used for physical examination, spinal immobilization, and post-lumbar puncture), Fowler positions (high Fowler 60-90 degrees for respiratory distress and eating, semi-Fowler 30-45 degrees for post-operative care and tube feeding, low Fowler 15-30 degrees for comfort), lateral (side-lying -- for unconscious patients to maintain airway, pressure relief, and administration of rectal medications or enemas), prone (lying face down -- used for ARDS patients to improve oxygenation, post-spinal surgery), Sims position (semi-prone -- for rectal examination and enema administration), Trendelenburg (head lower than feet -- for shock management, central line insertion), reverse Trendelenburg (head higher than feet -- for obese patients during intubation, reducing intracranial pressure), and lithotomy (supine with legs in stirrups -- for gynecological and urological procedures). The practical nurse must assess the patient's condition, surgical site, respiratory status, and hemodynamic stability before positioning and reposition immobile patients at minimum every 2 hours to prevent pressure injuries." },
    riskFactors: ["Pressure injuries from prolonged immobility: high-risk areas include sacrum, heels, ischial tuberosities, greater trochanters, occiput, and ears; risk increases with immobility, malnutrition, incontinence, decreased sensation, and impaired circulation", "Musculoskeletal injury to nurses from unsafe patient handling: back injuries are the most common occupational injury in nursing; lifting, transferring, and repositioning patients without proper equipment or techniques increases injury risk", "Respiratory compromise from improper positioning: supine position decreases functional residual capacity and increases work of breathing, especially in obese patients, post-operative patients, and those with respiratory disease", "Joint contractures from prolonged immobility without range of motion exercises or proper positioning: flexion contractures of hips, knees, and ankles develop within days to weeks of immobility", "Falls during transfers and ambulation: risk increased with weakness, orthostatic hypotension, sedating medications, unfamiliar environment, improper footwear, and wet floors", "Nerve injury from improper positioning during surgery or prolonged immobility: brachial plexus injury from arm abduction >90 degrees, peroneal nerve injury from lateral knee compression"],
    diagnostics: ["Braden Scale for pressure injury risk assessment: six subscales (sensory perception, moisture, activity, mobility, nutrition, friction/shear) scored 6-23; score <18 indicates at-risk, <14 moderate risk, <12 high risk, <9 very high risk -- reassess on admission, regularly, and with condition changes", "Skin assessment: perform thorough skin inspection on admission and every shift with attention to bony prominences; document any existing pressure injuries using NPUAP staging (Stage 1: non-blanchable erythema; Stage 2: partial thickness skin loss; Stage 3: full thickness skin loss; Stage 4: full thickness tissue loss with exposed bone/tendon; Unstageable: obscured by slough/eschar; Deep Tissue Pressure Injury: persistent non-blanchable deep red/maroon/purple discoloration)", "Functional mobility assessment: ability to reposition independently, transfer ability (bed to chair, stand-pivot, sliding board), ambulation status, weight-bearing restrictions, and need for assistive devices or mechanical lifting equipment", "Orthostatic vital signs: measure blood pressure and heart rate supine, then after standing for 1 and 3 minutes; positive orthostatic hypotension = systolic drop >20 mmHg or diastolic drop >10 mmHg or symptoms (dizziness, lightheadedness) -- indicates need for gradual position changes", "Body mechanics assessment of nursing staff: proper lifting techniques (wide base of support, bend at knees not waist, keep load close to body, engage core muscles, avoid twisting), use of mechanical lifting devices (ceiling lifts, sit-to-stand lifts, lateral transfer aids)", "Post-operative positioning requirements: assess surgical site, surgeon orders, and contraindicated positions (e.g., post-hip replacement precautions, post-craniotomy head elevation requirements, post-spinal surgery log-roll technique)"],
    management: ["Implement turning schedule: reposition immobile patients at minimum every 2 hours (every 1 hour if high-risk for pressure injury); use 30-degree lateral tilt positions to offload pressure from sacrum and trochanters; document all position changes", "Pressure redistribution surfaces: specialty mattresses (alternating pressure, low air loss, continuous lateral rotation therapy) for patients at high risk of pressure injury; seat cushions for wheelchair-bound patients; heel elevation devices (pillows or foam boots) to float heels off bed surface", "Safe patient handling equipment: use mechanical lifting devices (ceiling lifts, portable floor lifts, sit-to-stand lifts) instead of manual lifting whenever possible; follow facility safe patient handling policy; assess patient factors (weight, cooperation, weight-bearing ability, medical devices) to select appropriate equipment", "Post-operative positioning protocols: elevate head of bed 30-45 degrees after abdominal surgery to reduce diaphragmatic pressure and prevent aspiration; elevate surgical extremity above heart level to reduce edema; maintain hip precautions after total hip arthroplasty (no flexion >90 degrees, no adduction past midline, no internal rotation)", "Progressive mobilization: dangle at bedside before standing, standing before walking, short distances before long distances; monitor vital signs and symptoms with each progression; orthostatic precautions for patients at risk", "Range of motion exercises: active ROM (patient performs independently) or passive ROM (nurse moves joints through range) at minimum twice daily for immobile patients; focus on all major joints to prevent contractures"],
    nursingActions: ["Assess skin integrity at bony prominences on admission and every shift; document any pressure injury using NPUAP staging system; implement individualized prevention plan based on Braden Scale score including turning schedule, specialty surface, nutritional optimization, moisture management, and offloading devices", "Reposition immobile patients at minimum every 2 hours using a documented turning schedule; use 30-degree lateral tilt to redistribute pressure; ensure heels are elevated off the bed surface at all times using pillows or heel suspension devices", "Use proper body mechanics and mechanical lifting devices for all patient handling activities: assess patient's weight, mobility, cooperation, and medical devices to determine appropriate lift equipment; two-person assist or mechanical lift for patients who cannot bear weight or cooperate; NEVER manually lift a patient who exceeds safe limits", "Position patients therapeutically based on clinical indication: semi-Fowler or high Fowler for respiratory distress (optimizes diaphragmatic excursion), lateral recovery position for unconscious patients (maintains airway), elevate extremities for edema reduction, Trendelenburg for hypotension (controversial -- monitor response)", "Implement fall prevention during positioning and transfers: lock bed wheels and lower bed to lowest position, ensure non-slip footwear, use gait belt for ambulation assistance, clear pathway of obstacles, ensure adequate lighting, maintain two points of contact during transfers", "Educate patients and families on importance of position changes, pressure injury prevention, proper use of call bell before attempting to get up, bed exercise and ROM programs, and safe use of assistive devices (walker, cane, crutches)"]
  },

  "procedures-rpn": {
    title: "Common Clinical Procedures for Practical Nurses",
    cellular: { title: "Sterile Technique, Specimen Collection, and Procedural Skills", content: "Clinical procedures are systematic, evidence-based actions performed by the practical nurse to assess, monitor, or treat patients. Proficiency in procedural skills requires understanding of underlying anatomy and physiology, strict adherence to infection prevention principles, patient preparation and education, and accurate documentation. Aseptic technique is the foundation of safe procedural practice and includes two levels: surgical (sterile) asepsis -- the elimination of ALL microorganisms from an area, used for invasive procedures that penetrate sterile body cavities (wound care involving deep tissue, catheterization, surgical procedures) -- and medical asepsis (clean technique) -- the reduction of microorganisms to prevent their spread, used for most routine care activities. The principles of surgical asepsis include: a sterile field is created and maintained by sterile items only; sterile items touched by unsterile items become contaminated; sterile items out of vision or below waist level are considered contaminated; sterile fields become contaminated by prolonged exposure to air, moisture, or airborne particles; edges of sterile packages and containers are considered contaminated. Common procedures within practical nursing scope include vital signs measurement, venipuncture and IV cannulation, urinary catheterization, wound care and dressing changes, nasogastric tube insertion and management, specimen collection (blood, urine, stool, sputum, wound cultures), medication administration by all routes, suctioning (oral, nasopharyngeal, tracheal), and oxygen therapy administration." },
    riskFactors: ["Catheter-associated urinary tract infection (CAUTI): risk increases 3-7% per day of catheterization; indwelling catheters should be used only when clinically indicated and removed as soon as possible", "Needlestick injuries and bloodborne pathogen exposure: risk during venipuncture, IV insertion, and injection procedures; always activate safety-engineered sharps devices immediately after use, never recap needles", "Surgical site infection from breaks in sterile technique during wound care and invasive procedures", "Patient injury from improper technique: urethral trauma during catheterization, pneumothorax from central line insertion assistance, aspiration during nasogastric tube feedings, extravasation from infiltrated IV", "Specimen collection errors: incorrect patient identification (leading to wrong-patient results), improper collection technique (contamination), incorrect specimen handling or labeling (affecting result accuracy), hemolysis from improper venipuncture technique", "Anxiety and pain associated with procedures: inadequate patient preparation and education, failure to provide analgesia or anxiolysis before painful procedures"],
    diagnostics: ["Urinalysis interpretation: color (pale yellow normal, dark amber concentrated, red/brown hematuria or myoglobinuria, cloudy indicating pyuria), specific gravity (1.005-1.030, concentrated >1.030 dehydration, dilute <1.005 overhydration), pH (4.5-8.0), protein (negative normal, positive in kidney disease), glucose (negative normal, positive in uncontrolled diabetes), leukocyte esterase and nitrites (positive in UTI), RBCs, WBCs, casts, bacteria", "Blood specimen interpretation: CBC (hemoglobin, hematocrit, WBC with differential, platelet count), basic metabolic panel (electrolytes, BUN, creatinine, glucose), liver function tests (AST, ALT, alkaline phosphatase, bilirubin, albumin), coagulation studies (PT/INR, aPTT)", "Wound assessment documentation: wound type (surgical, pressure, traumatic, venous, arterial, diabetic), location, measurements (length x width x depth in cm), wound bed description (percentage of granulation, slough, eschar), exudate (type: serous, serosanguineous, sanguineous, purulent; amount: none, scant, small, moderate, large), surrounding skin condition, tunneling or undermining, pain level", "IV site assessment using the phlebitis scale: 0 (no symptoms), 1 (erythema at site with or without pain), 2 (pain with erythema and/or edema), 3 (pain with erythema, streak formation, palpable cord), 4 (pain with erythema, streak formation, palpable cord >1 inch, purulent drainage); remove IV and restart at new site for grade 2 or higher", "Nasogastric tube placement verification: pH testing of aspirate (<5.5 indicates gastric placement), X-ray confirmation for initial placement or if pH inconclusive; auscultation alone is NOT a reliable method for tube placement verification", "Oxygen saturation monitoring via pulse oximetry: normal SpO2 94-100% (88-92% target for COPD patients at risk of CO2 retention); factors affecting accuracy include poor perfusion, dark nail polish, motion artifact, carbon monoxide exposure, and hypothermia"],
    management: ["Urinary catheterization: use aseptic technique with sterile equipment; clean meatus with antiseptic solution; use smallest gauge catheter appropriate; inflate balloon with correct sterile water volume; secure catheter to prevent traction; maintain closed drainage system below bladder level at all times", "Wound care management: select dressing based on wound characteristics (moist wound healing principle); negative pressure wound therapy (VAC) for complex wounds; sharp debridement by qualified practitioners; topical antimicrobials (silver dressings, honey, cadexomer iodine) for critically colonized wounds", "IV therapy management: select appropriate gauge cannula (18-20G for most adults, 16G for blood products and rapid fluid resuscitation, 22-24G for pediatric and elderly with fragile veins); secure with transparent dressing; assess site every shift; rotate peripheral sites every 72-96 hours or per policy", "Specimen collection technique: proper patient identification with two identifiers, correct container and preservative for each test, aseptic technique for sterile specimens, proper labeling at bedside, timely transport to laboratory, and awareness of pre-analytical factors affecting results", "Oxygen therapy administration: select delivery device based on oxygen requirements -- low flow (nasal cannula 1-6 L/min delivering 24-44% FiO2, simple mask 5-10 L/min delivering 40-60% FiO2) or high flow (non-rebreather mask 10-15 L/min delivering 80-95% FiO2, Venturi mask for precise FiO2 delivery)", "Nasogastric tube management: verify placement before each use, irrigate with 30 mL normal saline before and after medications, crush medications thoroughly and administer separately (never crush enteric-coated or sustained-release formulations), clamp tube for 30 minutes after medication administration"],
    nursingActions: ["Perform hand hygiene before and after every procedure; set up sterile fields correctly maintaining principles of surgical asepsis; identify and discard any item whose sterility is in question -- when in doubt, consider it contaminated", "Verify patient identity using two identifiers before every procedure and specimen collection; label all specimens at the bedside immediately after collection; document the procedure performed, patient tolerance, and any findings", "Maintain urinary catheter care bundle: daily assessment of continued need for catheterization (document indication), perineal care at minimum every shift and after bowel movements, keep drainage bag below bladder level and off the floor, maintain closed system integrity, secure catheter to upper thigh (female) or abdomen (male) to prevent traction", "Perform wound assessments and dressing changes using appropriate technique (sterile for deep wounds, clean for chronic wounds as per evidence); measure and document wound characteristics accurately; report signs of infection (increasing erythema, warmth, edema, purulent drainage, odor, increasing pain)", "Monitor IV sites at minimum every shift and with each medication administration: assess for infiltration (swelling, coolness, pallor -- stop infusion immediately), phlebitis (redness, warmth, pain along vein, palpable cord -- remove and restart), and extravasation (vesicant drug leakage causing tissue damage -- stop infusion, aspirate residual drug, apply appropriate antidote)", "Administer oxygen therapy as prescribed: ensure correct flow rate and delivery device, monitor SpO2 and respiratory assessment, educate patients on oxygen safety (no smoking, keep away from open flames, maintain humidification for flow rates >4 L/min via nasal cannula)"],
    signs: { left: ["Clean surgical wound healing by primary intention with well-approximated edges, no signs of infection, and normal progression through inflammatory, proliferative, and remodeling phases", "Patient with short-term indwelling catheter successfully removed with return of normal voiding pattern and no signs of urinary tract infection", "Peripheral IV functioning well with no signs of infiltration or phlebitis, infusing prescribed fluids and medications at correct rate"], right: ["IV extravasation of vesicant medication (chemotherapy, vasopressors, calcium, potassium): tissue necrosis and potential need for surgical intervention -- STOP infusion immediately, aspirate residual drug, do NOT flush, apply specific antidote per protocol, notify physician", "Tension pneumothorax during or after central line insertion: sudden severe respiratory distress, tracheal deviation away from affected side, absent breath sounds on affected side, hypotension, distended neck veins -- life-threatening emergency requiring immediate needle decompression", "Catheter-associated urosepsis: acute onset fever, rigors, tachycardia, hypotension originating from urinary catheter infection -- remove catheter, obtain cultures, initiate sepsis protocol", "Air embolism from IV line or central venous catheter disconnection: sudden dyspnea, chest pain, altered consciousness -- clamp catheter, position patient left lateral decumbent with head down (Durant maneuver), administer high-flow oxygen, notify emergency team"] }
  },

  "renal-rpn": {
    title: "Renal System Foundations",
    cellular: { title: "Kidney Anatomy, Function, and Common Renal Disorders", content: "The kidneys are paired, bean-shaped organs located retroperitoneally in the upper abdomen that perform essential homeostatic functions: filtration of metabolic waste products (urea, creatinine, uric acid) from the blood, regulation of fluid volume and osmolality, electrolyte balance (sodium, potassium, calcium, phosphorus), acid-base balance (bicarbonate reabsorption and hydrogen ion excretion), blood pressure regulation (through the renin-angiotensin-aldosterone system and fluid volume control), erythropoietin production (stimulating red blood cell production in the bone marrow), and activation of vitamin D (calcitriol, necessary for calcium absorption). The functional unit of the kidney is the nephron, of which each kidney contains approximately one million. Each nephron consists of the glomerulus (a tuft of capillaries within Bowman capsule where blood is filtered under hydrostatic pressure -- approximately 180 liters of filtrate produced daily), the proximal convoluted tubule (reabsorption of 65% of filtered sodium, water, glucose, amino acids, bicarbonate), the loop of Henle (countercurrent mechanism establishing the medullary concentration gradient for urine concentration), the distal convoluted tubule (fine-tuning of sodium, potassium, and acid-base balance under aldosterone and PTH influence), and the collecting duct (final urine concentration under ADH influence). Normal urine output is 0.5-1 mL/kg/hr; oliguria (<0.5 mL/kg/hr or <400 mL/day) and anuria (<100 mL/day) are indicators of renal impairment requiring urgent evaluation. Common renal disorders include acute kidney injury (AKI), chronic kidney disease (CKD), nephrotic syndrome, nephritic syndrome, urinary tract infections, and kidney stones (nephrolithiasis)." },
    riskFactors: ["Diabetes mellitus -- the leading cause of chronic kidney disease and end-stage renal disease; hyperglycemia damages glomerular capillaries (diabetic nephropathy) over years", "Hypertension -- the second leading cause of CKD; sustained elevated blood pressure damages renal arterioles and glomeruli (hypertensive nephrosclerosis); target BP <130/80 mmHg for CKD patients", "Nephrotoxic medications: NSAIDs (reduce renal blood flow), aminoglycosides (gentamicin -- direct tubular toxicity), contrast dye (contrast-induced nephropathy), ACE inhibitors/ARBs (beneficial long-term but can cause acute GFR decline), lithium, amphotericin B", "Acute kidney injury risk factors: hypovolemia (dehydration, hemorrhage), sepsis, major surgery (especially cardiac and vascular), urinary obstruction (kidney stones, BPH, tumors), rhabdomyolysis", "Chronic kidney disease progression factors: uncontrolled diabetes and hypertension, high protein diet, smoking, obesity, recurrent UTIs, family history of kidney disease, advancing age (GFR declines approximately 1 mL/min/year after age 40)", "Kidney stone risk factors: dehydration (most important modifiable risk), high sodium diet, high oxalate foods, family history, hyperparathyroidism, recurrent UTIs, certain medications (indinavir, topiramate)"],
    diagnostics: ["Serum creatinine and estimated GFR (eGFR): creatinine (53-106 umol/L normal, varies by age, sex, and muscle mass); eGFR calculated from creatinine, age, sex, and race; CKD staging: Stage 1 eGFR >90, Stage 2 60-89, Stage 3a 45-59, Stage 3b 30-44, Stage 4 15-29, Stage 5 <15 (ESRD requiring dialysis or transplant)", "Blood urea nitrogen (BUN): 2.9-8.2 mmol/L; elevated in renal failure, dehydration, GI bleeding, high protein diet; BUN:creatinine ratio >20:1 suggests prerenal azotemia (dehydration, heart failure)", "Urinalysis: proteinuria (>300 mg/day indicates significant kidney damage), hematuria (microscopic or gross -- glomerulonephritis, stones, malignancy), casts (RBC casts in glomerulonephritis, WBC casts in pyelonephritis, waxy casts in CKD), specific gravity, glucose, nitrites and leukocyte esterase", "Urine albumin-to-creatinine ratio (ACR): <3 mg/mmol normal, 3-30 mg/mmol moderately increased (microalbuminuria -- earliest sign of diabetic nephropathy), >30 mg/mmol severely increased (macroalbuminuria)", "Serum electrolytes in renal failure: hyperkalemia (most dangerous -- cardiac arrhythmia risk), hyperphosphatemia (calcium-phosphorus product elevation causing vascular calcification), hypocalcemia (from decreased vitamin D activation), metabolic acidosis (from decreased acid excretion)", "Renal imaging: ultrasound (kidney size, hydronephrosis, cysts, masses -- first-line imaging), CT scan without contrast for kidney stones (contrast avoided in renal impairment), renal biopsy for glomerular disease diagnosis"],
    management: ["CKD management to slow progression: strict blood glucose control (HbA1c <7% for most diabetic patients), blood pressure management (target <130/80, ACE inhibitor or ARB as first-line renoprotective agents -- monitor potassium and creatinine after initiation), sodium restriction (<2000 mg/day), protein restriction in advanced CKD (0.6-0.8 g/kg/day)", "AKI management: identify and treat underlying cause (prerenal -- IV fluid resuscitation; intrarenal -- discontinue nephrotoxins; postrenal -- relieve obstruction); monitor fluid balance strictly; adjust medication doses for renal function; avoid nephrotoxic agents; renal replacement therapy if indicated", "Electrolyte management in renal failure: restrict dietary potassium (<2000-3000 mg/day), phosphate binders with meals (calcium carbonate, sevelamer), vitamin D supplementation (calcitriol for CKD), sodium bicarbonate for metabolic acidosis, potassium-binding resins for hyperkalemia", "Anemia management in CKD: erythropoiesis-stimulating agents (ESA -- epoetin alfa, darbepoetin), iron supplementation (IV iron preferred in dialysis patients), target hemoglobin 100-115 g/L (avoid >130 g/L due to increased cardiovascular risk)", "Kidney stone management: acute pain management (NSAIDs first-line for renal colic if renal function adequate, opioids if needed), hydration to promote stone passage, alpha-blocker (tamsulosin) for medical expulsive therapy for stones 5-10 mm, surgical intervention for stones >10 mm or complicated stones", "Renal replacement therapy options: hemodialysis (3x/week, 3-4 hours), peritoneal dialysis (daily, patient-performed exchanges), kidney transplant (best outcomes for eligible patients -- living donor preferred)"],
    nursingActions: ["Monitor intake and output meticulously in patients with renal impairment: measure and document all sources of intake (oral, IV, tube feedings) and output (urine, drainage, emesis, diarrhea); report urine output <0.5 mL/kg/hr for 2 consecutive hours (early indicator of AKI)", "Obtain daily weights at the same time, same scale, same clothing -- weight is the most reliable indicator of fluid status; report weight gain >1 kg/day (approximately 1 liter fluid retention); compare with intake/output records for consistency", "Monitor and report critical laboratory values: potassium >6.0 mEq/L (cardiac arrhythmia risk -- assess ECG for peaked T waves, widened QRS), creatinine rapidly rising (AKI), BUN significantly elevated, metabolic acidosis (pH <7.35 with low bicarbonate)", "Review all medications for renal dosing adjustments: many drugs are renally cleared and require dose reduction or interval extension in CKD; coordinate with pharmacy for renal dosing recommendations; avoid nephrotoxic agents when possible (NSAIDs, aminoglycosides, contrast dye)", "Educate CKD patients on dietary restrictions: potassium restriction (avoid bananas, oranges, potatoes, tomatoes, salt substitutes), phosphorus restriction (avoid dairy, cola, processed foods), sodium restriction (<2000 mg/day), fluid restriction if advised, and protein modification based on CKD stage", "Assess for complications of advanced CKD: uremic symptoms (fatigue, anorexia, nausea, pruritus, peripheral neuropathy, altered mentation), volume overload (edema, hypertension, pulmonary congestion), pericarditis (chest pain, friction rub -- medical emergency), and bone disease (secondary hyperparathyroidism, pathological fractures)"],
    signs: { left: ["CKD Stage 3 managed with blood pressure control, ACE inhibitor therapy, dietary modifications, and regular monitoring with stable eGFR", "Acute kidney injury from dehydration resolving with IV fluid resuscitation and return of normal urine output and creatinine to baseline", "Patient with kidney stone passing spontaneously with adequate pain management and hydration"], right: ["Severe hyperkalemia (K+ >6.5 mEq/L) with ECG changes: peaked T waves, prolonged PR, widened QRS, loss of P waves, sine wave pattern -- cardiac arrest imminent; emergency treatment: IV calcium gluconate (membrane stabilization), insulin + glucose (intracellular potassium shift), nebulized salbuterol, sodium bicarbonate, kayexalate, and emergent dialysis", "Uremic pericarditis: chest pain, pericardial friction rub, fever in patient with advanced untreated CKD -- indication for urgent dialysis initiation; risk of cardiac tamponade if untreated", "Acute pulmonary edema from fluid overload in oliguric/anuric renal failure: severe dyspnea, orthopnea, pink frothy sputum, crackles throughout, hypoxia -- requires emergent dialysis or ultrafiltration, IV furosemide (may be ineffective in severe renal failure), oxygen, and morphine", "Contrast-induced nephropathy: acute creatinine rise within 24-72 hours of contrast administration -- prevention with pre-procedure IV hydration (0.9% NaCl) and use of lowest contrast volume is essential in at-risk patients"] },
    medications: [
      { name: "Ramipril (Altace)", type: "ACE inhibitor", action: "Inhibits angiotensin-converting enzyme (ACE), preventing conversion of angiotensin I to angiotensin II. Reduces systemic vasoconstriction, aldosterone secretion, and sodium/water retention, lowering blood pressure. In the kidney, selectively dilates the efferent arteriole, reducing intraglomerular pressure and proteinuria, slowing CKD progression. First-line renoprotective agent for diabetic and proteinuric kidney disease.", sideEffects: "Dry persistent cough (most common reason for discontinuation, caused by bradykinin accumulation -- switch to ARB if intolerable), hyperkalemia (monitor potassium especially in CKD and with potassium supplements/sparing diuretics), hypotension (especially first dose -- start low, go slow), acute kidney injury (transient creatinine rise up to 30% is acceptable and expected upon initiation), angioedema (rare but potentially life-threatening -- more common in Black patients)", contra: "Pregnancy (teratogenic -- causes fetal renal agenesis, oligohydramnios, skull defects), bilateral renal artery stenosis (can precipitate acute renal failure), history of ACE inhibitor-induced angioedema, hyperkalemia (K+ >5.5 mEq/L)", pearl: "Check baseline creatinine and potassium before starting; recheck within 1-2 weeks of initiation or dose change; a creatinine rise up to 30% from baseline is expected and acceptable (indicates the drug is working to reduce glomerular pressure); discontinue if creatinine rises >30% or potassium >5.5; ensure adequate hydration before starting; contraindicated in pregnancy -- counsel women of childbearing age about contraception" },
      { name: "Furosemide (Lasix)", type: "Loop diuretic", action: "Inhibits the sodium-potassium-chloride cotransporter (NKCC2) in the thick ascending limb of the loop of Henle, blocking reabsorption of approximately 25% of filtered sodium, producing potent diuresis. Used in CKD for volume management when GFR is too low for thiazide diuretics to be effective. Higher doses often required in renal failure due to decreased drug delivery to the tubular lumen.", sideEffects: "Hypokalemia (monitor closely, supplement as needed), hypomagnesemia, hypocalcemia, ototoxicity (especially with rapid IV administration or high doses, concurrent aminoglycosides), dehydration and hypotension, metabolic alkalosis, hyperglycemia, hyperuricemia (can precipitate gout)", contra: "Anuria unresponsive to diuretics (indicates renal replacement therapy needed), severe electrolyte depletion, hepatic coma, sulfonamide allergy (cross-reactivity possible though rare)", pearl: "In CKD, higher doses are needed: start with 40-80 mg IV and double dose if no response within 2 hours (ceiling effect dose varies by GFR); IV push rate should not exceed 4 mg/min to prevent ototoxicity; give in morning to avoid nocturia; monitor daily weight (best indicator of fluid status), electrolytes, and renal function; ineffective when GFR <5 mL/min -- dialysis needed at that point" }
    ]
  },

  "safety-ethics-rpn": {
    title: "Patient Safety and Ethical Practice",
    cellular: { title: "Safety Culture, Ethical Decision-Making, and Professional Standards", content: "Patient safety and ethical practice are intertwined foundations of competent nursing care. A culture of safety recognizes that errors in healthcare are often system-related rather than individual failures, and promotes reporting, learning, and continuous improvement rather than blame. The Swiss Cheese Model (James Reason) illustrates how adverse events occur when multiple layers of defense (policies, procedures, training, technology, human vigilance) all have weaknesses ('holes') that align, allowing a hazard to reach the patient. Key safety concepts include: Just Culture (distinguishing between human error, at-risk behavior, and reckless behavior with appropriate responses to each), root cause analysis (systematic investigation of adverse events to identify contributing factors and implement corrective actions), and high reliability organizations (achieving consistently safe performance through preoccupation with failure, reluctance to simplify, sensitivity to operations, commitment to resilience, and deference to expertise). Ethical nursing practice is guided by four fundamental bioethical principles: autonomy (respecting the patient's right to make informed decisions about their own care, including the right to refuse treatment), beneficence (acting in the patient's best interest to do good), non-maleficence (the obligation to do no harm), and justice (fair distribution of resources and equitable treatment regardless of personal characteristics). Additional ethical concepts essential for practical nursing include: informed consent (patient's voluntary agreement to treatment based on adequate information about the procedure, risks, benefits, and alternatives), confidentiality (protecting patient health information under PHIPA/PIPEDA in Canada), advance directives (patient's documented wishes regarding future healthcare decisions when they may be unable to communicate), and mandatory reporting obligations (abuse, neglect, communicable diseases, unsafe professional practice). The practical nurse must integrate safety practices and ethical principles into every aspect of patient care." },
    riskFactors: ["Communication failures: identified as the leading root cause of sentinel events; includes inadequate handoff communication, failure to escalate concerns, unclear orders, and language barriers", "Medication errors: wrong patient, drug, dose, route, or time; contributing factors include similar drug names (look-alike/sound-alike), interruptions during medication preparation, inadequate patient identification, and workarounds that bypass safety systems", "Falls: leading cause of patient harm in healthcare facilities; risk factors include medications (sedatives, antihypertensives, diuretics), impaired mobility, cognitive impairment, environmental hazards, and inadequate supervision", "Healthcare-associated infections: resulting from breaks in infection prevention practices, inadequate hand hygiene compliance, improper isolation precautions, and antibiotic resistance", "Alarm fatigue: desensitization to clinical alarms due to excessive false and non-actionable alarms, leading to missed critical alerts and delayed response to genuine deterioration", "Ethical challenges: end-of-life decision-making, resource allocation, conflicts between patient autonomy and beneficence, mandatory reporting obligations, confidentiality versus duty to warn, informed consent in cognitively impaired patients"],
    diagnostics: ["Incident/occurrence reporting: documentation of any event that resulted in or had the potential to result in patient harm, including near misses; reports are used for system improvement, not punitive action in a Just Culture framework", "Root cause analysis (RCA): systematic investigation methodology used after sentinel events to identify contributing factors at the individual, team, environment, organization, and regulatory levels; generates actionable recommendations to prevent recurrence", "Safety culture surveys: validated tools (Hospital Survey on Patient Safety Culture, Safety Attitudes Questionnaire) measuring staff perceptions of teamwork, communication, management support, incident reporting, and organizational learning", "Failure mode and effects analysis (FMEA): proactive risk assessment tool used to identify potential failure points in processes BEFORE adverse events occur; prioritizes risks based on severity, probability, and detectability", "Ethics consultation: referral to hospital ethics committee for complex ethical dilemmas including treatment futility, surrogate decision-making disputes, resource allocation conflicts, and conscientious objection", "Regulatory compliance audits: assessment of adherence to standards of practice, organizational policies, accreditation requirements, and legislative obligations (PHIPA, Occupational Health and Safety Act, mandatory reporting requirements)"],
    management: ["Implement standardized communication tools: SBAR (Situation, Background, Assessment, Recommendation) for all clinical communication, structured handoff using I-PASS (Illness severity, Patient summary, Action list, Situation awareness, Synthesis by receiver), read-back of verbal and telephone orders", "Medication safety practices: independent double-check for high-alert medications (insulin, anticoagulants, concentrated electrolytes, opioids, chemotherapy), barcode medication administration systems, 'do not use' abbreviation list, tall man lettering for look-alike/sound-alike drugs", "Fall prevention programs: individualized risk assessment on admission and regularly (Morse Fall Scale), patient and family education, environmental modifications (bed alarm, non-slip footwear, clear pathways), toileting schedules, medication review, exercise and balance programs", "Ethical decision-making framework: identify the ethical problem; gather relevant facts (medical, social, patient preferences, legal considerations); identify ethical principles involved; explore options; make and implement decision; evaluate outcome and process", "Advance care planning: facilitate goals of care conversations early in serious illness; document advance directives, substitute decision-maker, and resuscitation status; ensure documentation is accessible and communicated to all team members", "Professional accountability: maintain competence through continuing education, practice within scope, report unsafe practice or impaired colleagues (duty to report), maintain professional boundaries, and seek guidance when faced with situations beyond competence"],
    nursingActions: ["Verify patient identity using two identifiers (name and date of birth) before every medication administration, procedure, specimen collection, blood product transfusion, and treatment -- this is a fundamental safety practice that must never be bypassed", "Perform safety checks before leaving every patient's room: bed in lowest position, wheels locked, call bell within reach, personal items accessible, side rails per policy, environment clear of hazards, adequate lighting; this is known as the 'safe room check'", "Report all incidents, near misses, and safety concerns through the organizational reporting system promptly and completely -- reporting is a professional obligation that contributes to system improvement and patient safety; do not fear punitive consequences in a Just Culture environment", "Practice within scope of practice as defined by provincial/territorial nursing regulatory body; consult with registered nurses, physicians, or other team members when patient situations exceed practical nurse competence; never perform a procedure for which you have not received education and demonstrated competency", "Maintain patient confidentiality: share patient information only with healthcare team members involved in the patient's care and on a need-to-know basis; do not discuss patient information in public areas; follow organizational policies for electronic health record access and social media use", "Ensure informed consent is obtained before procedures: verify that the physician has explained the procedure, risks, benefits, and alternatives; the patient's consent is voluntary and informed; the patient has capacity to make the decision; document the consent process; advocate for the patient if consent appears inadequate or coerced"],
    signs: { left: ["Active safety culture with open reporting, learning from incidents, and implementation of evidence-based safety practices", "Patient exercising autonomous decision-making with full informed consent and healthcare team respecting and supporting their choices", "Ethical dilemma resolved through collaborative ethics consultation with all stakeholders' perspectives considered and patient's values honored"], right: ["Sentinel event: unexpected death, permanent harm, or serious temporary harm requiring intervention -- triggers immediate root cause analysis, patient/family disclosure, and corrective action implementation", "Patient refusing life-sustaining treatment: ethical obligation to respect autonomous decision if patient has capacity, is fully informed, and decision is voluntary -- document thoroughly, ensure palliative comfort measures, provide emotional support", "Suspected elder abuse or child abuse: mandatory reporting obligation regardless of patient or family wishes -- report to appropriate authorities (Children's Aid Society, Adult Protective Services) as required by law; document objective findings", "Medication error causing patient harm: immediately assess patient, provide necessary treatment, notify physician, report through incident reporting system, disclose to patient/family (duty of candor), participate in root cause analysis, and implement corrective actions to prevent recurrence"] }
  },

  "skin-rpn": {
    title: "Integumentary System Foundations",
    cellular: { title: "Skin Anatomy, Common Dermatological Conditions, and Wound Healing", content: "The integumentary system -- the body's largest organ -- consists of the skin and its accessory structures (hair, nails, sweat glands, sebaceous glands) and performs vital protective, regulatory, and sensory functions. The skin has three layers: the epidermis (outermost layer composed of stratified squamous epithelium; contains keratinocytes producing keratin for waterproofing, melanocytes producing melanin for UV protection, Langerhans cells for immune surveillance, and Merkel cells for tactile sensation; renews approximately every 28 days in young adults, slowing with age), the dermis (beneath the epidermis; composed of connective tissue containing collagen and elastin fibers providing strength and elasticity, blood vessels, lymphatics, nerve endings, hair follicles, and sweat and sebaceous glands), and the hypodermis or subcutaneous layer (adipose tissue providing insulation, cushioning, and energy storage). The skin's functions include: barrier protection against pathogens, chemicals, and UV radiation; thermoregulation through vasodilation/vasoconstriction and sweat production; sensation (pain, pressure, temperature, touch); vitamin D synthesis (UV exposure converts 7-dehydrocholesterol to vitamin D3); fluid and electrolyte balance; and immune surveillance. Wound healing proceeds through four overlapping phases: hemostasis (platelet plug and fibrin clot formation, seconds to hours), inflammation (vasodilation, increased permeability, neutrophil and macrophage migration to clear debris and pathogens, days 1-6), proliferation (granulation tissue formation, angiogenesis, collagen synthesis by fibroblasts, epithelialization, wound contraction, days 4-24), and remodeling/maturation (collagen reorganization and scar maturation, 21 days to 2 years -- maximum tensile strength approximately 80% of original). Wound healing can occur by primary intention (wound edges approximated, e.g., surgical incision), secondary intention (wound left open to heal from the bottom up, e.g., pressure injury), or tertiary intention (delayed primary closure -- wound initially left open for drainage/debridement then later closed)." },
    riskFactors: ["Pressure injury risk factors: immobility (most significant risk factor), malnutrition (especially protein deficiency), incontinence (moisture damage), decreased sensory perception, shear and friction forces, advanced age (thinned epidermis, decreased collagen), chronic diseases (diabetes, vascular disease)", "Impaired wound healing: diabetes mellitus (hyperglycemia impairs neutrophil function, fibroblast activity, and collagen synthesis), peripheral vascular disease (inadequate oxygen and nutrient delivery), malnutrition (protein, vitamin C, zinc, and iron deficiency), immunosuppression (corticosteroids, chemotherapy), smoking (nicotine causes vasoconstriction reducing tissue perfusion), obesity, advanced age", "Skin cancer risk: excessive UV exposure (sunburns, tanning beds), fair skin, family history, multiple atypical moles, immunosuppression, history of radiation therapy; melanoma risk increases with blistering sunburns in childhood", "Skin breakdown in hospitalized patients: surgical incisions, medical devices causing pressure (nasogastric tubes, oxygen masks, casts, restraints), adhesive injuries from tape and dressings, moisture-associated skin damage from incontinence", "Contact dermatitis: occupational exposure (healthcare workers, cleaners), latex allergy, topical medications, cosmetics, metals (nickel)", "Age-related skin changes increasing vulnerability: thinned epidermis, decreased collagen and elastin, reduced subcutaneous fat, decreased sebaceous gland activity (dry skin), slower wound healing, decreased immune surveillance"],
    diagnostics: ["Comprehensive skin assessment: inspect all body surfaces including posterior surfaces, skin folds, between toes, and scalp; assess color, temperature, moisture, turgor, texture, and presence of lesions; describe lesions using standard terminology (macule, papule, vesicle, pustule, plaque, nodule, ulcer) including size, shape, color, distribution, and configuration", "Pressure injury staging (NPUAP/EPUAP): Stage 1 (non-blanchable erythema of intact skin), Stage 2 (partial thickness skin loss -- shallow open ulcer or intact/ruptured blister), Stage 3 (full thickness skin loss -- subcutaneous fat may be visible), Stage 4 (full thickness tissue loss with exposed bone, tendon, or muscle), Unstageable (wound bed obscured by slough or eschar), Deep Tissue Pressure Injury (persistent non-blanchable deep red, maroon, or purple discoloration of intact or non-intact skin)", "Wound measurement and documentation: measure length (head to toe direction) x width (side to side) x depth (deepest point) in centimeters using consistent technique; photograph with measuring ruler and patient consent; assess tunneling (narrow channel) and undermining (tissue destruction under wound edges) using clock-face notation", "Braden Scale for pressure injury risk assessment: six subscales scored 6-23 (sensory perception, moisture, activity, mobility, nutrition, friction/shear); implement prevention interventions based on total score", "Laboratory markers relevant to skin integrity: serum albumin and prealbumin (nutritional markers affecting healing), HbA1c (glycemic control in diabetic patients), white blood cell count (infection), wound culture and sensitivity (for clinically infected wounds -- not routine colonization swabs)", "Ankle-brachial index (ABI) for lower extremity ulcers: ABI >0.9 normal, 0.5-0.9 arterial insufficiency (compression therapy contraindicated if <0.5), <0.5 severe arterial disease (surgical referral needed)"],
    management: ["Pressure injury prevention bundle: risk assessment on admission and regularly, reposition every 2 hours (30-degree lateral tilt), pressure redistribution mattress for at-risk patients, heel offloading, nutritional optimization (protein 1.25-1.5 g/kg/day, vitamin C, zinc), moisture management (barrier cream, continence care), minimize shear and friction (use lifting devices, keep HOB <30 degrees when possible)", "Moist wound healing: select dressings that maintain optimal wound moisture -- too dry delays healing, too wet causes maceration; common dressing types include hydrocolloid (autolytic debridement, partial thickness wounds), foam (moderate-heavy exudate absorption), alginate (heavy exudate, packing wounds), hydrogel (hydration of dry wounds, pain relief), silver-containing (antimicrobial for critically colonized/infected wounds), transparent film (superficial wounds, IV site protection)", "Wound debridement: removal of necrotic tissue to promote healing; methods include autolytic (moisture-retentive dressings over slough), enzymatic (collagenase ointment), mechanical (wet-to-dry dressings -- no longer recommended as first-line), sharp/surgical (by qualified practitioner for thick eschar)", "Negative pressure wound therapy (NPWT/VAC therapy): applies controlled sub-atmospheric pressure to wound bed, promoting granulation tissue formation, removing exudate, reducing edema, and increasing blood flow; used for chronic and complex wounds, dehisced surgical wounds, and skin grafts", "Skin cancer screening and prevention: regular skin self-examination using ABCDE criteria for melanoma (Asymmetry, Border irregularity, Color variation, Diameter >6mm, Evolving), sun protection (SPF 30+ sunscreen, protective clothing, avoid peak UV hours), referral for biopsy of suspicious lesions", "Topical treatments for common skin conditions: emollients for dry skin and eczema, topical corticosteroids for inflammatory dermatoses (use lowest potency effective, limited duration on face and skin folds), antifungal agents for fungal infections, antibacterial ointments for minor wound infection prophylaxis"],
    nursingActions: ["Perform comprehensive skin assessment on admission and every shift: inspect all skin surfaces with attention to bony prominences (sacrum, heels, ischial tuberosities, greater trochanters, occiput), skin folds, and under medical devices; document findings and report any new skin breakdown immediately", "Implement individualized pressure injury prevention plan based on Braden Scale risk assessment: turning schedule with documentation, pressure redistribution surface, nutritional referral for optimization, moisture management, heel offloading, and minimizing shear/friction during repositioning", "Perform wound care using appropriate technique: assess wound characteristics at each dressing change, select dressing based on wound bed condition and exudate level, apply dressings using clean or sterile technique as indicated, secure without adhesive injury, and document wound status", "Manage moisture-associated skin damage: implement structured incontinence skin care protocol (gentle cleansing with pH-balanced cleanser, thorough drying, barrier cream application), change wet/soiled linens promptly, use incontinence containment products appropriately", "Monitor for wound infection: assess for clinical signs (increasing pain, erythema spreading beyond wound margins, warmth, edema, purulent or malodorous drainage, delayed healing, systemic signs of fever and elevated WBC) -- obtain wound culture from wound bed using Levine technique if infection suspected", "Educate patients and families on skin care and wound prevention: importance of nutrition for skin integrity, regular position changes, skin inspection (especially for patients with decreased sensation -- diabetes, spinal cord injury), sun protection, and proper wound care at home after discharge"]
  },

  "wound-care-rpn": {
    title: "Wound Care and Management",
    cellular: { title: "Wound Assessment, Dressing Selection, and Healing Optimization", content: "Wound care is a core practical nursing competency requiring knowledge of wound physiology, systematic assessment, evidence-based dressing selection, and patient education. Wounds are classified by etiology: surgical (intentional incisions), traumatic (lacerations, abrasions, avulsions, punctures, burns), pressure injuries (sustained pressure causing tissue ischemia), vascular ulcers (arterial insufficiency with poor blood supply, or venous insufficiency with venous hypertension and edema), diabetic ulcers (neuropathy-related, typically on plantar foot surfaces), and moisture-associated skin damage (incontinence-associated dermatitis). The TIME framework guides wound bed preparation for chronic wounds: T (Tissue -- is the wound bed viable? Remove necrotic tissue through debridement), I (Infection/Inflammation -- is infection or excessive inflammation present? Control bioburden with antimicrobials, address host factors), M (Moisture -- is the moisture balance optimal? Select dressings to maintain moist wound healing without maceration), and E (Edge -- are wound edges advancing? Assess for undermining, rolled edges indicating stalled healing, consider advanced therapies if edges not progressing). Wound healing by secondary intention (open wounds healing from the base up) requires granulation tissue formation (beefy red, moist, granular tissue indicating healthy healing), followed by epithelialization (new epithelial cells migrating across wound surface from wound edges), and wound contraction (myofibroblasts pull wound edges inward). The practical nurse must accurately assess and document wound characteristics, select and apply appropriate dressings, monitor for complications, and educate patients on wound self-management." },
    riskFactors: ["Factors impairing wound healing: diabetes mellitus (hyperglycemia inhibits WBC function and collagen synthesis), peripheral arterial disease (ABI <0.5 indicates severe ischemia), venous insufficiency (edema impairs oxygen delivery), malnutrition (protein, vitamin C, zinc, iron deficiency), smoking (nicotine vasoconstriction and carbon monoxide reducing oxygen-carrying capacity), immunosuppression (corticosteroids, chemotherapy), obesity, advanced age, radiation therapy", "Wound infection risk: contaminated or dirty wounds, large tissue defects, foreign bodies, devitalized tissue, wound with poor blood supply, immunocompromised host, diabetes, prolonged operative time, implanted devices", "Chronic wound development: wound failing to progress through normal healing phases within expected timeframe (typically >4-6 weeks); may be stalled in inflammatory phase due to persistent infection, biofilm formation, moisture imbalance, or unaddressed underlying cause", "Surgical wound complications: dehiscence (wound edges separate -- risk factors include obesity, malnutrition, infection, coughing/straining, diabetes), evisceration (dehiscence with organ protrusion through wound -- cover with sterile saline-moistened dressing, emergency surgical closure required), seroma, hematoma, infection", "Biofilm formation: bacteria encased in protective polysaccharide matrix that is resistant to antibiotics and host immune defenses; present in majority of chronic wounds; requires aggressive wound bed preparation and debridement", "Skin adhesive injury and medical device-related pressure injury from prolonged contact with tapes, dressings, tubes, oxygen devices, and other medical equipment"],
    diagnostics: ["Wound assessment documentation: wound type and etiology, location (anatomical landmarks), dimensions (length x width x depth in cm), wound bed tissue type and percentage (granulation -- red/beefy, slough -- yellow/tan, eschar -- black/brown, epithelial -- pink/pearl), exudate characteristics (type: serous, serosanguineous, sanguineous, purulent; amount: none, scant, small, moderate, large/copious)", "Periwound skin assessment: inspect surrounding skin within 4 cm of wound edge for maceration (white, waterlogged from excess moisture), erythema (redness indicating inflammation or infection spreading), induration (hardness), excoriation, skin stripping from adhesives, and callus formation (diabetic foot ulcers)", "Tunneling and undermining measurement: use sterile probe to assess depth and direction of tunneling (narrow channel extending from wound bed) using clock-face notation (12 o'clock = toward head); undermining measured by gently probing under intact wound edges", "Wound infection assessment: clinical signs of infection include increased pain, expanding erythema, warmth, swelling, purulent or increased exudate, malodorous drainage, delayed healing, friable granulation tissue, wound breakdown; systemic signs include fever, elevated WBC, elevated CRP", "Wound photography with standardized technique: consistent positioning, lighting, distance, wound ruler in frame, patient identifiers, date; provides objective comparison over time", "Vascular assessment for lower extremity wounds: peripheral pulse palpation, capillary refill time, ankle-brachial index (ABI -- essential before applying compression therapy), edema assessment, skin color and temperature changes with elevation versus dependency"],
    management: ["Moist wound healing principle: evidence-based standard of care; appropriate moisture promotes epithelial cell migration, autolytic debridement, angiogenesis, and growth factor activity while preventing wound bed desiccation and cellular death", "Dressing selection based on wound characteristics: dry wounds need hydration (hydrogel, honey), moderate exudate needs absorption (foam, hydrofiber), heavy exudate needs high absorption (alginate, super-absorbent), infected/critically colonized wounds need antimicrobial dressings (silver, iodine), necrotic tissue needs debridement (autolytic with occlusive dressing, enzymatic with collagenase)", "Compression therapy for venous leg ulcers: multi-layer compression bandaging or compression stockings to address underlying venous hypertension; contraindicated if ABI <0.5 (severe arterial disease); target 30-40 mmHg compression at ankle", "Offloading for diabetic foot ulcers: total contact casting (gold standard), removable cast walkers, therapeutic footwear to redistribute pressure away from ulcer site; reduce plantar pressure to promote healing", "Negative pressure wound therapy (NPWT): controlled sub-atmospheric pressure applied via sealed dressing system; promotes granulation, removes exudate, reduces bacterial colonization; used for acute and chronic wounds, dehisced surgical wounds, preparation for skin grafting", "Nutritional optimization for wound healing: protein 1.25-1.5 g/kg/day (essential for collagen synthesis), vitamin C 250-500 mg twice daily (cofactor for collagen synthesis), zinc 220 mg daily (supports immune function and cell proliferation), adequate caloric intake to meet metabolic demands of healing"],
    nursingActions: ["Assess and document wound characteristics at every dressing change using consistent measurement technique and terminology; compare with previous assessments to evaluate healing trajectory; a wound that is not showing improvement within 2-4 weeks of appropriate treatment requires reassessment of diagnosis, treatment plan, and patient factors", "Select and apply wound dressings based on wound assessment findings using the moist wound healing principle: match dressing absorptive capacity to exudate level, choose antimicrobial dressings for clinically infected or critically colonized wounds, protect periwound skin with barrier products, and secure dressings without causing adhesive skin injury", "Perform wound cleansing with warmed normal saline or potable water using gentle irrigation pressure (4-15 psi -- achieved with 35 mL syringe and 19-gauge angiocatheter) to remove surface debris without damaging granulation tissue; avoid antiseptics (povidone-iodine, hydrogen peroxide, Dakin solution) on clean granulating wounds as they are cytotoxic to healing cells", "Monitor and address factors that impair wound healing: optimize blood glucose control in diabetic patients (target HbA1c <7%), ensure adequate nutrition (refer to dietitian), encourage smoking cessation, manage edema, ensure pressure offloading for pressure injuries and diabetic ulcers, treat wound infection appropriately", "Educate patients and caregivers on wound self-management at home: hand hygiene before and after wound care, dressing change technique and frequency, signs of infection requiring medical attention (increasing pain, redness, swelling, drainage, fever), medication adherence, nutritional requirements, activity modifications, and follow-up appointment importance", "Implement surgical wound care protocols: monitor surgical incision for signs of healing and complications (infection, dehiscence, hematoma, seroma); manage surgical drains (Jackson-Pratt, Hemovac, Penrose) including measuring and documenting output, maintaining suction, and strip drains per policy; remove sutures or staples as ordered with assessment of wound closure adequacy"]
  }
};

